fun main() {
    val colors = listOf("Red", "Green", "Blue", "Yellow")

    // Manual iterator
    val iter = colors.iterator()
    while (iter.hasNext()) {
        println("Color: ${iter.next()}")
    }

    // Mutable iterator with removal
    val numbers = mutableListOf(10, 20, 30, 40, 50)
    val mutIter = numbers.iterator()
    while (mutIter.hasNext()) {
        if (mutIter.next() > 30) {
            mutIter.remove()
        }
    }
    println("After removal: $numbers")
}
